function solve(nums, k) {
    const prefixSums = [0];
    for (const num of nums) {
        prefixSums.push((prefixSums[prefixSums.length - 1] + num) % k);
    }

    const count = new Array(k).fill(0);
    for (const sum of prefixSums) {
        count[sum]++;
    }

    let result = 0;
    for (let i = 0; i < k; i++) {
        if (count[i] > 0) {
            result += (i * count[i]);
        }
    }

    return result;
}

